local leftX = -5.230 local rightX = 5.092 local y = 0.431 local areaWidth = rightX - leftX local positions = {}
for i = 1, spawnCount do local randomX = (_UtilLogic:RandomIntegerRange(0, 100) / 100) * areaWidth + leftX positions[i] = Vector3(randomX, y, 0) end
return positions
